def classify_precise(char_start, char_end, matn, text):
    left = text[max(0, char_start-40):char_start]
    right = text[char_end:char_end+40]
    # define patterns
    ayah_immediate_cues = ["قال الله تعالى", "قال الله", "قال تعالى", "في سورة", "سورة", "البقرة", "(البقرة"]
    hadeeth_immediate_cues = ["قال النبي", "قال رسول", "قال رسول الله", "قال النبي محمد", "قال النبي صلى الله عليه وسلم", "قال النبي محمد صلى الله عليه وسلم", "قال النبي صلى الله عليه و", "في الحديث", "رواه", "روى", "أخرجه", "البخاري", "مسلم"]
    # check left
    for cue in ayah_immediate_cues:
        if cue in left:
            return "Aya", left, right
    for cue in hadeeth_immediate_cues:
        if cue in left:
            return "Hadeeth", left, right
    # check right
    for cue in ayah_immediate_cues:
        if cue in right:
            return "Aya", left, right
    for cue in hadeeth_immediate_cues:
        if cue in right:
            return "Hadeeth", left, right
    # Now check ±64
    left64 = text[max(0, char_start-64):char_start]
    right64 = text[char_end:char_end+64]
    ctx = left64 + right64
    ayah_found = any(c in ctx for c in ayah_cues)
    had_found = any(c in ctx for c in hadeeth_cues)
    if ayah_found and not had_found:
        return "Aya", left64, right64
    if had_found and not ayah_found:
        return "Hadeeth", left64, right64
    # both present: classify by MATN itself heuristically:
    # If matn contains 'سبحان' or 'الرحمن' maybe Ayah; but better: check for classical Quranic diacritics 'ٰ' (superscript Alef) or presence of wide tashkeel. But unreliable.
    # We'll use common pattern: Quranic verses often contain Hamzat al-Wasl? Not reliable.
    # Instead check nearby immediate left if it includes 'قال' followed by 'الله' or 'النبي'. We did above.
    # Fallback: if right context includes "رواه" prefer Hadeeth, else if contains parentheses with surah name prefer Aya
    if "رواه" in ctx or "البخاري" in ctx or "مسلم" in ctx:
        return "Hadeeth", left64, right64
    if "سورة" in ctx or "البقرة" in ctx or "(" in right64:
        return "Aya", left64, right64
    # final fallback: decide by common hadith patterns: starting with 'من' often hadith command e.g., "من كان يؤمن بالله..." but 'من' also common in quran
    # But looking at our MATNs, the one ambiguous earlier is "مثل البخيل..." which should be Hadeeth. We can check if immediate left contains 'الحديث' or 'قال النبي' etc; but we already checked.
    # So default to Hadeeth
    return "Hadeeth", left64, right64

